// ============================================================
// Attach Department Token
// Multi-agency pattern: each department publishes with its OWN
// bearer token. n8n's built-in credential picker is static (one
// credential per node) so for a per-row/per-department token we
// build the Authorization header value here instead, and pass it
// downstream as a field the HTTP Request node reads via expression.
//
// IMPORTANT (teaching note): in a real deployment these tokens
// should NOT be hardcoded in a Code node like this either — pull
// them from n8n environment variables or a credentials vault.
// They are inlined here only as placeholders for the lab.
// ============================================================

const TOKEN_MAP = {
  CSE:  'REPLACE_WITH_CSE_DEPT_TOKEN',
  ECE:  'REPLACE_WITH_ECE_DEPT_TOKEN',
  MECH: 'REPLACE_WITH_MECH_DEPT_TOKEN',
  CIVIL:'REPLACE_WITH_CIVIL_DEPT_TOKEN',
  IT:   'REPLACE_WITH_IT_DEPT_TOKEN'
  // ...extend up to all 10 departments, one unique token each
};

const row = $input.item.json;
const deptCode = (row.Department_Code || '').toString().trim().toUpperCase();
const token = TOKEN_MAP[deptCode] || null;

if (!token) {
  throw new Error(`No token configured for department: ${deptCode}`);
}

// Build the JSON payload that will be POSTed to the display board server.
// Kept as a plain object here; the HTTP Request node sends it as the JSON body.
const payload = {
  entry_id: row.Entry_ID,
  student_name: row.Student_Name,
  roll_no: row.Roll_No,
  department: deptCode,
  company_name: row.Company_Name,
  package_lpa: row.Package_LPA,
  selection_date: row.Selection_Date,
  display_message: row.Display_Message
};

return {
  json: {
    ...row,
    department_code: deptCode,
    auth_header_value: 'Bearer ' + token,
    payload
  }
};
